const raw = $json.body ?? $json.data ?? $json.response ?? $json;
const text = String(raw).trim();
if (!text) return [];

const lines = text.split(/\r?\n/).filter(Boolean);
const headers = lines[0].split(',').map(h => h.trim());
const rows = [];

const dateIdx = headers.findIndex(h => /date|time/i.test(h));
const titleIdx = headers.findIndex(h => /title|headline|news/i.test(h));

for (const line of lines.slice(1)) {
  const cols = line.split(',');
  if (dateIdx < 0 || titleIdx < 0) continue;
  const date = (cols[dateIdx] ?? '').trim();
  const title = (cols[titleIdx] ?? '').trim();
  if (!date || !title) continue;
  rows.push({ date, title });
}

rows.sort((a, b) => new Date(a.date) - new Date(b.date));
return rows.map(r => ({ json: r }));

const grouped = new Map();
for (const item of $input.all()) {
  const date = item.json.date;
  const title = item.json.title;
  if (!date || !title) continue;
  if (!grouped.has(date)) grouped.set(date, []);
  grouped.get(date).push(title);
}

const out = [];
for (const [date, titles] of grouped.entries()) {
  out.push({ json: { date, news_titles: titles, news_joined: titles.join(' | ') } });
}
out.sort((a, b) => new Date(a.json.date) - new Date(b.json.date));
return out;

function rollingMean(arr, idx, w) {
  const from = Math.max(0, idx - w + 1);
  const slice = arr.slice(from, idx + 1);
  const s = slice.reduce((a, b) => a + b, 0);
  return s / slice.length;
}

function rollingStd(arr, idx, w) {
  const from = Math.max(0, idx - w + 1);
  const slice = arr.slice(from, idx + 1);
  const m = slice.reduce((a, b) => a + b, 0) / slice.length;
  const v = slice.reduce((a, b) => a + (b - m) ** 2, 0) / slice.length;
  return Math.sqrt(v);
}

function calcRsi(closes, idx, period = 14) {
  if (idx === 0) return 50;
  const from = Math.max(1, idx - period + 1);
  let gain = 0;
  let loss = 0;
  for (let i = from; i <= idx; i++) {
    const d = closes[i] - closes[i - 1];
    if (d >= 0) gain += d;
    else loss += -d;
  }
  const avgGain = gain / period;
  const avgLoss = loss / period;
  if (avgLoss === 0) return 100;
  const rs = avgGain / avgLoss;
  return 100 - (100 / (1 + rs));
}

const all = $input.all();
const market = all
  .filter(x => x.json.close !== undefined)
  .map(x => ({ date: String(x.json.date), close: Number(x.json.close) }))
  .filter(x => x.date && Number.isFinite(x.close))
  .sort((a, b) => new Date(a.date) - new Date(b.date));

const newsMap = new Map();
for (const n of all.filter(x => x.json.news_titles !== undefined)) {
  newsMap.set(String(n.json.date), n.json.news_titles || []);
}

const closes = market.map(x => x.close);
const out = market.map((row, i) => {
  const sma20 = rollingMean(closes, i, 20);
  const std20 = rollingStd(closes, i, 20);
  const bbUpper = sma20 + 2 * std20;
  const bbLower = sma20 - 2 * std20;
  const sma50 = rollingMean(closes, i, 50);
  const rsi = calcRsi(closes, i, 14);
  const newsTitles = newsMap.get(row.date) || [];

  return {
    json: {
      date: row.date,
      close: row.close,
      rsi,
      sma_50: sma50,
      bb_upper: bbUpper,
      bb_lower: bbLower,
      news_titles: newsTitles,
      news_joined: newsTitles.join(' | '),
    },
  };
});

return out;

const symbol = $env.SYMBOL || 'BTCUSDT';
const timeframe = $env.TIMEFRAME || '1d';
const model = $env.HF_MODEL || 'mistralai/Mistral-7B-Instruct-v0.3';

return $input.all().map(item => {
  const row = item.json;
  const prompt = [
    'You are a cautious financial analyst assistant.',
    'Return strict JSON: fear_greed (0..100), sentiment_label, sentiment_score (-1..1), analysis_short.',
    `Symbol: ${symbol}`,
    `Timeframe: ${timeframe}`,
    `RSI: ${Number(row.rsi).toFixed(2)}`,
    `SMA_50: ${Number(row.sma_50).toFixed(4)}`,
    `Price: ${Number(row.close).toFixed(4)}`,
    `Recent News: ${row.news_joined || 'none'}`,
  ].join('\n');

  return {
    json: {
      ...row,
      symbol,
      timeframe,
      hf_payload: {
        model,
        messages: [
          { role: 'system', content: 'You are a cautious trading assistant. Educational analysis only.' },
          { role: 'user', content: prompt },
        ],
        temperature: 0.1,
        max_tokens: 220,
      },
    },
  };
});

function parseMaybeJson(text) {
  try { return JSON.parse(text); } catch {}
  const m = String(text || '').match(/\{[\s\S]*\}/);
  if (!m) return null;
  try { return JSON.parse(m[0]); } catch { return null; }
}

function clamp(x, lo, hi) { return Math.max(lo, Math.min(hi, x)); }

const prepared = $items('4. Prepare Batch', 0, 0).map(i => i.json);
const responses = $input.all().map(i => i.json);

const rows = [];
for (let i = 0; i < prepared.length; i++) {
  const row = prepared[i] || {};
  const resp = responses[i] || {};

  let llm = null;
  if (resp.choices && Array.isArray(resp.choices) && resp.choices.length > 0) {
    llm = parseMaybeJson(resp.choices[0]?.message?.content || '');
  } else if (resp.data?.choices && Array.isArray(resp.data.choices)) {
    llm = parseMaybeJson(resp.data.choices[0]?.message?.content || '');
  }

  const sentimentScore = Number(llm?.sentiment_score ?? 0);
  const fearGreed = Number(llm?.fear_greed ?? (50 + sentimentScore * 35));

  const rsi = Number(row.rsi ?? 50);
  const close = Number(row.close ?? 0);
  const bbUpper = Number(row.bb_upper ?? close);
  const bbLower = Number(row.bb_lower ?? close);

  const signalA = rsi >= 70 ? 'SELL' : rsi <= 30 ? 'BUY' : 'HOLD';

  let signalB = 'HOLD';
  if (fearGreed >= 80 && rsi >= 70 && close >= bbUpper) signalB = 'SELL';
  else if (fearGreed <= 20 && rsi <= 30 && close <= bbLower) signalB = 'BUY';
  else if (fearGreed >= 60 && sentimentScore >= 0.2 && rsi >= 25) signalB = 'SELL';
  else if (fearGreed <= 40 && sentimentScore <= -0.2 && rsi <= 55) signalB = 'BUY';
  else if (sentimentScore >= 0.25 && rsi <= 45) signalB = 'BUY';
  else if (sentimentScore <= -0.25 && rsi >= 55) signalB = 'SELL';

  rows.push({
    date: row.date,
    close,
    rsi,
    bb_lower: bbLower,
    bb_upper: bbUpper,
    fear_greed: clamp(fearGreed, 0, 100),
    sentiment_score: clamp(sentimentScore, -1, 1),
    signal_a: signalA,
    signal_b: signalB,
  });
}

rows.sort((a, b) => new Date(a.date) - new Date(b.date));

let posA = 0;
let posB = 0;
let prevClose = null;
let cumA = 0;
let cumB = 0;
let totalTrades = 0;

const outRows = [];
for (const r of rows) {
  const prevPosB = posB;

  if (r.signal_a === 'BUY') posA = 1;
  if (r.signal_a === 'SELL') posA = -1;
  if (r.signal_b === 'BUY') posB = 1;
  if (r.signal_b === 'SELL') posB = -1;

  if (prevPosB !== posB && prevClose !== null) totalTrades++;

  const ret = prevClose ? (r.close - prevClose) / prevClose : 0;
  const dailyA = (prevClose ? posA : 0) * ret;
  const dailyB = (prevClose ? posB : 0) * ret;

  cumA = (1 + cumA) * (1 + dailyA) - 1;
  cumB = (1 + cumB) * (1 + dailyB) - 1;

  outRows.push({
    ...r,
    pos_a: posA,
    pos_b: posB,
    daily_a: dailyA,
    daily_b: dailyB,
    cum_a: cumA,
    cum_b: cumB,
  });

  prevClose = r.close;
}

const dailyBSeries = outRows.map(r => Number(r.daily_b || 0));
const positive = dailyBSeries.filter(x => x > 0);
const negative = dailyBSeries.filter(x => x < 0);
const winRate = dailyBSeries.length ? (positive.length / dailyBSeries.length) * 100 : 0;
const profit = positive.reduce((a, b) => a + b, 0);
const loss = Math.abs(negative.reduce((a, b) => a + b, 0));
const profitFactor = loss > 0 ? profit / loss : (profit > 0 ? 999 : 0);

const avg = dailyBSeries.length ? dailyBSeries.reduce((a, b) => a + b, 0) / dailyBSeries.length : 0;
const var_ = dailyBSeries.length ? dailyBSeries.reduce((a, b) => a + (b - avg) ** 2, 0) / dailyBSeries.length : 0;
const std = Math.sqrt(var_);
const sharpe = std > 0 ? (avg / std) * Math.sqrt(365) : 0;

let peak = -Infinity;
let mdd = 0;
for (const r of outRows) {
  const eq = 1 + Number(r.cum_b || 0);
  if (eq > peak) peak = eq;
  const dd = peak > 0 ? (peak - eq) / peak : 0;
  if (dd > mdd) mdd = dd;
}

const totalReturn = outRows.length ? Number(outRows[outRows.length - 1].cum_b || 0) * 100 : 0;
const finalBalance = 10000 * (1 + (outRows.length ? Number(outRows[outRows.length - 1].cum_b || 0) : 0));

return [{
  json: {
    metric_summary: {
      'Total Trades': totalTrades,
      'Win Rate': winRate.toFixed(2) + '%',
      'Profit Factor': profitFactor.toFixed(2),
      'Total Return': totalReturn.toFixed(2) + '%',
      'Sharpe Ratio': sharpe.toFixed(2),
      'Max Drawdown': '-' + (mdd * 100).toFixed(2) + '%',
      'Final Balance': '$' + finalBalance.toFixed(2),
    },
    trade_log: outRows,
  },
}];

const input = $input.first().json;
const trades = input.trade_log || [];
const summary = input.metric_summary || {};

const tradeHeader = 'date,close,rsi,fear_greed,sentiment_score,signal_a,signal_b,daily_b,cum_b\n';
const tradeRows = trades.map(t => [
  t.date,
  t.close,
  Number(t.rsi ?? 0).toFixed(2),
  Number(t.fear_greed ?? 0).toFixed(2),
  Number(t.sentiment_score ?? 0).toFixed(4),
  t.signal_a,
  t.signal_b,
  Number(t.daily_b ?? 0).toFixed(6),
  Number(t.cum_b ?? 0).toFixed(6),
].join(','));
const tradeCsv = tradeHeader + tradeRows.join('\n');

const metricsHeader = 'Metric,Value\n';
const metricsRows = Object.entries(summary).map(([k, v]) => `${k},${v}`).join('\n');
const metricsCsv = metricsHeader + metricsRows;

return [{
  json: {
    message: 'CSV files ready',
    metric_summary: summary,
    latest_signal_a: trades.length ? trades[trades.length - 1].signal_a : 'n/a',
    latest_signal_b: trades.length ? trades[trades.length - 1].signal_b : 'n/a',
  },
  binary: {
    trade_log: {
      data: Buffer.from(tradeCsv).toString('base64'),
      mimeType: 'text/csv',
      fileName: 'trade_log.csv',
    },
    metrics: {
      data: Buffer.from(metricsCsv).toString('base64'),
      mimeType: 'text/csv',
      fileName: 'metrics.csv',
    },
  },
}];

const summary = $json.metric_summary || {};
const text = [
  '?? n8n run completed',
  `Total Trades: ${summary['Total Trades'] ?? 'n/a'}`,
  `Win Rate: ${summary['Win Rate'] ?? 'n/a'}`,
  `Sharpe Ratio: ${summary['Sharpe Ratio'] ?? 'n/a'}`,
  `Total Return: ${summary['Total Return'] ?? 'n/a'}`,
  `Latest A: ${$json.latest_signal_a ?? 'n/a'}`,
  `Latest B: ${$json.latest_signal_b ?? 'n/a'}`,
].join('\n');

return [{ json: { ...$json, telegram_text: text } }];
